toml_template:
[[instances]]
targets = [{{range $i, $v := split .targets ","}}{{if $i}}, {{end}}"{{trim $v}}"{{end}}]
protocol = "{{.protocol}}"
timeout = "{{.timeout}}"
{{- if .send}}
send = "{{.send}}"
{{- end}}
{{- if .expect}}
expect = "{{.expect}}"
{{- end}}
interval = "{{.interval}}"

[instances.connectivity]
severity = "Critical"
